/**
 * Shared test helper for inspecting hooks.json entries.
 *
 * CC 2.1.139 introduced two valid shapes for hook entries:
 *
 *   Legacy string form:  { command: "node ${ROOT}/run-hook.mjs path/entry" }
 *   Exec args form:      { command: "node", args: ["${ROOT}/run-hook.mjs", "path/entry"] }
 *
 * Most tests want to assert something about the resolved invocation
 * ("does this hook entry call run-hook.mjs?", "is the entry path X?").
 * `commandPath` returns the whitespace-joined token list, which behaves
 * identically against both shapes so existing `.includes("...")` checks
 * continue to work after the args[] migration (M138 #1774).
 */
export interface HookEntryShape {
  readonly command?: unknown;
  readonly args?: unknown;
}

/**
 * Return the resolved command + args as a single whitespace-joined string.
 * Empty string when the entry has neither — or when called with undefined.
 * Accepting undefined keeps test sites tidy when piping through `.find(...)`
 * results without requiring a non-null assertion at every callsite.
 */
export function commandPath(entry: HookEntryShape | undefined | null): string {
  if (!entry) return '';
  const cmd = typeof entry.command === 'string' ? entry.command : '';
  const args = Array.isArray(entry.args) ? entry.args.filter((a): a is string => typeof a === 'string') : [];
  if (args.length === 0) return cmd;
  return cmd ? `${cmd} ${args.join(' ')}` : args.join(' ');
}
